const user = null;

// ❌ Crashes
console.log(user.profile.name); // TypeError: Cannot read properties of null

// ✅ Short-circuits safely
console.log(user?.profile?.name); // undefined — no crash

const user = {
  name: 'Alice',
  address: null,
};

console.log(user?.name);              // 'Alice'  — user exists
console.log(user?.address?.city);     // undefined — address is null, short-circuits
console.log(user?.phone?.number);     // undefined — phone doesn't exist

const user = { greet: () => 'Hello!' };
const guest = {};

console.log(user.greet?.());   // 'Hello!'
console.log(guest.greet?.());  // undefined — greet doesn't exist, call is skipped

// Without ?.
guest.greet(); // TypeError: guest.greet is not a function

const data = null;

console.log(data?.[0]);       // undefined — data is null
console.log(data?.[0]?.name); // undefined — safe chain

const items = ['apple', 'banana'];
console.log(items?.[1]);      // 'banana' — items exists, normal access

// Scenario: user's custom font size preference (0 is NOT valid, so || is fine)
const fontSize = userPrefs.fontSize || 16;

// Scenario: user's score in a game (0 IS a valid score)
const score = game.score ?? 'Not started'; // || would replace a score of 0!

// Scenario: feature flag (false IS a valid, intentional value)
const darkMode = settings.darkMode ?? true; // ?? preserves false; || would override it

const user = null;

// Chain: try to get the value, fall back if undefined/null
const name = user?.profile?.displayName ?? 'Guest';
console.log(name); // 'Guest'

const city = user?.address?.city ?? 'Unknown location';
console.log(city); // 'Unknown location'

// With a method call:
const initials = user?.getInitials?.() ?? '?';
console.log(initials); // '?'

function UserCard({ user }) {
  // user is null while loading from API
  return (
    <div className="card">
      <img
        src={user?.avatar ?? '/placeholder.png'}
        alt={user?.name ?? 'Loading...'}
      />
      <h2>{user?.name ?? 'Loading...'}</h2>
      <p>{user?.bio ?? 'No bio available.'}</p>
      <span>{user?.location?.city ?? 'Location unknown'}</span>
    </div>
  );
}

// Optional callback props — parent might not pass onChange
function Slider({ value, onChange }) {
  function handleChange(e) {
    // Only call onChange if the parent provided it
    onChange?.(Number(e.target.value));
  }

  return <input type="range" value={value} onChange={handleChange} />;
}

function OrderSummary({ order }) {
  // API response may have optional nested fields
  const customerName = order?.customer?.profile?.fullName ?? 'Unknown Customer';
  const shippingCity = order?.shipping?.address?.city ?? 'N/A';
  const discountCode = order?.promo?.code ?? 'None applied';
  const itemCount = order?.items?.length ?? 0;

  return (
    <div>
      <p>Customer: {customerName}</p>
      <p>Ship to: {shippingCity}</p>
      <p>Promo: {discountCode}</p>
      <p>Items: {itemCount}</p>
    </div>
  );
}

function Button({ label, size, disabled, onClick }) {
  // Use ?? to preserve false (disabled=false should not be replaced by default)
  const isDisabled = disabled ?? false;
  const buttonSize = size ?? 'medium';

  return (
    <button
      className={`btn btn-${buttonSize}`}
      disabled={isDisabled}
      onClick={onClick}
    >
      {label ?? 'Click me'}
    </button>
  );
}

let config = null;
config ??= { theme: 'dark', lang: 'en' };
console.log(config); // { theme: 'dark', lang: 'en' }

let score = 0;
score ??= 100; // score is 0, not null/undefined — not replaced
console.log(score); // 0

// ❌ || replaces 0 and false — valid values get overridden
function ProgressBar({ value, visible }) {
  const pct = value || 0;        // if value is 0, stays 0 — same here, but...
  const show = visible || true;  // if visible is false, becomes true — WRONG!

  // ✅ Use ?? to preserve intended falsy values
  const pct2 = value ?? 0;       // only replaces null/undefined
  const show2 = visible ?? true; // preserves false
}

// ❌ Unnecessary — if you know items is always an array, ?. adds noise
const length = items?.length;

// ✅ Use ?. only where null/undefined is genuinely possible
const length = items.length;

// But if items comes from an API response that might be null:
const length = response?.items?.length ?? 0;

// ?. only short-circuits for null/undefined, not for 0, '', or false
const str = '';
console.log(str?.toUpperCase()); // '' (str exists, just empty — NOT short-circuited)

const n = 0;
console.log(n?.toFixed(2)); // '0.00' (0 is not null/undefined — method is called)
